configuration.expression:
var totalSpaces = 100;

var occ = occupied_spaces;
if (occ == null) { occ = 0; }
if (occ instanceof String) { occ = Double.parseDouble(occ); }
if (occ < 0) { occ = 0; }
if (occ > totalSpaces) { occ = totalSpaces; }

var freeSpaces = totalSpaces - occ;
var occupancyRate = (occ / totalSpaces) * 100;

var basePrice = base_price_per_hour;
if (basePrice == null) { basePrice = 2.0; }
if (basePrice instanceof String) { basePrice = Double.parseDouble(basePrice); }

var duration = requested_duration_hours;
if (duration == null) { duration = 1; }
if (duration instanceof String) { duration = Double.parseDouble(duration); }

var priceFactor = 1.0;
var demandLevel = "LOW";
if (occupancyRate < 50) { priceFactor = 1.0; demandLevel = "LOW"; }
else if (occupancyRate < 80) { priceFactor = 1.2; demandLevel = "MEDIUM"; }
else if (occupancyRate < 95) { priceFactor = 1.5; demandLevel = "HIGH"; }
else { priceFactor = 2.0; demandLevel = "CRITICAL"; }

var currentPrice = basePrice * priceFactor;
var bookingPrice = currentPrice * duration;

var status = booking_status;
if (status == null) { status = "no_booking_request"; }

var reservedSpaceId = "none";
if (status == "requested") {
  if (freeSpaces > 0) {
    status = "confirmed";
    reservedSpaceId = "P-" + (occ + 1);
    occ = occ + 1;
    freeSpaces = totalSpaces - occ;
    occupancyRate = (occ / totalSpaces) * 100;
  } else {
    status = "rejected";
  }
}

var displayStatus = "AVAILABLE";
var displayMessage = freeSpaces + " Plätze frei – Buchung möglich";
if (freeSpaces <= 0) {
  displayStatus = "FULL";
  displayMessage = "Parkhaus voll – keine Buchung möglich";
} else if (freeSpaces <= 10) {
  displayStatus = "LIMITED";
  displayMessage = "Nur noch " + freeSpaces + " Plätze frei";
}

return {
  "total_spaces": totalSpaces,
  "occupied_spaces": occ,
  "free_spaces": freeSpaces,
  "occupancy_rate": Math.round(occupancyRate * 100) / 100,
  "current_price_per_hour": Math.round(currentPrice * 100) / 100,
  "booking_price": Math.round(bookingPrice * 100) / 100,
  "demand_level": demandLevel,
  "booking_status": status,
  "reserved_space_id": reservedSpaceId,
  "display_status": displayStatus,
  "display_message": displayMessage
};
